_NP_WEIGHTS = None
_STATEFUL_NP_AGENT = None
_STATEFUL_NP_PLAYER = None
_LAST_STEP = None
_NHEAD = 4
_DMODEL = 64
_HEAD_DIM = _DMODEL // _NHEAD
_LN_EPS = 1e-5


def _load_np_weights():
    global _NP_WEIGHTS
    if _NP_WEIGHTS is None:
        if _MODEL_STATE_B64 is not None:
            payload = _base64.b64decode(_MODEL_STATE_B64.encode('ascii'))
            z = np.load(_io.BytesIO(payload))
            _NP_WEIGHTS = {k.replace('__', '.'): z[k].astype(np.float32) for k in z.files}
            return _NP_WEIGHTS
        raise FileNotFoundError('could not load weights.npz')
    return _NP_WEIGHTS


def _linear(x, weight, bias):
    return x @ weight.T + bias


def _layer_norm(x, weight, bias):
    mean = x.mean(axis=-1, keepdims=True)
    var = ((x - mean) ** 2).mean(axis=-1, keepdims=True)
    return ((x - mean) / np.sqrt(var + _LN_EPS)) * weight + bias


def _gelu(x):
    return 0.5 * x * (1.0 + np.tanh(0.7978845608028654 * (x + 0.044715 * x * x * x)))


def _softmax(x, axis=-1):
    x = x - np.max(x, axis=axis, keepdims=True)
    ex = np.exp(x)
    return ex / np.sum(ex, axis=axis, keepdims=True)


def _self_attn(x, w, prefix):
    qkv = _linear(
        x,
        w[prefix + '.self_attn.in_proj_weight'],
        w[prefix + '.self_attn.in_proj_bias'],
    )
    q, k, v = np.split(qkv, 3, axis=-1)
    seq = x.shape[0]
    q = q.reshape(seq, _NHEAD, _HEAD_DIM).transpose(1, 0, 2)
    k = k.reshape(seq, _NHEAD, _HEAD_DIM).transpose(1, 0, 2)
    v = v.reshape(seq, _NHEAD, _HEAD_DIM).transpose(1, 0, 2)
    scores = (q @ k.transpose(0, 2, 1)) / math.sqrt(_HEAD_DIM)
    attn = _softmax(scores, axis=-1)
    out = (attn @ v).transpose(1, 0, 2).reshape(seq, _DMODEL)
    return _linear(
        out,
        w[prefix + '.self_attn.out_proj.weight'],
        w[prefix + '.self_attn.out_proj.bias'],
    )


def _encoder_layer(x, w, layer_idx):
    prefix = f'encoder.layers.{layer_idx}'
    x = _layer_norm(
        x + _self_attn(x, w, prefix),
        w[prefix + '.norm1.weight'],
        w[prefix + '.norm1.bias'],
    )
    ff = _linear(x, w[prefix + '.linear1.weight'], w[prefix + '.linear1.bias'])
    ff = _gelu(ff)
    ff = _linear(ff, w[prefix + '.linear2.weight'], w[prefix + '.linear2.bias'])
    return _layer_norm(
        x + ff,
        w[prefix + '.norm2.weight'],
        w[prefix + '.norm2.bias'],
    )


def _np_action_policy(edge_features, action_mask):
    w = _load_np_weights()
    candidate_limit = 64
    flat_mask = action_mask.reshape(-1).astype(bool)
    candidate_idx = np.nonzero(flat_mask)[0]
    if candidate_limit is not None and candidate_idx.size > candidate_limit:
        flat_features = edge_features.reshape(N_MAX_DEFAULT * N_MAX_DEFAULT, FEATURE_DIM)
        cand = flat_features[candidate_idx]
        # Fast local prior: favor high-value low-cost edges before the neural rerank.
        eta = cand[:, FEATURE_ETA]
        ships_needed = cand[:, FEATURE_SHIPS_NEEDED]
        prod = cand[:, FEATURE_TGT_PRODUCTION]
        kind_attack = cand[:, FEATURE_KIND_ATTACK_ENEMY] + cand[:, FEATURE_KIND_ATTACK_NEUTRAL]
        kind_reinforce = cand[:, FEATURE_KIND_REINFORCE]
        src_ships = cand[:, FEATURE_SRC_SHIPS]
        score = (
            2.0 * kind_attack * prod / (ships_needed + eta + 1.0)
            + 0.25 * kind_reinforce
            + 0.02 * src_ships
            - 0.01 * eta
        )
        keep = np.argpartition(score, -candidate_limit)[-candidate_limit:]
        candidate_idx = candidate_idx[keep[np.argsort(score[keep])[::-1]]]
    else:
        flat_features = edge_features.reshape(N_MAX_DEFAULT * N_MAX_DEFAULT, FEATURE_DIM)
    tokens = (flat_features[candidate_idx].astype(np.float32) / FEATURE_SCALES.reshape(1, -1))
    x = _linear(tokens, w['edge_embed.weight'], w['edge_embed.bias'])
    for layer_idx in range(3):
        x = _encoder_layer(x, w, layer_idx)
    move_logits = _linear(x, w['policy_head.weight'], w['policy_head.bias']).reshape(-1)
    pooled = x.mean(axis=0, keepdims=True)
    stop_logit = float(_linear(pooled, w['stop_head.weight'], w['stop_head.bias'])[0, 0])
    masked = np.full(N_MAX_DEFAULT * N_MAX_DEFAULT, -1.0e9, dtype=np.float32)
    masked[candidate_idx] = move_logits.astype(np.float32)
    logits = np.concatenate([masked, np.asarray([stop_logit], dtype=np.float32)])
    return _softmax(logits, axis=0)


def np_model_agent_actions(obs, max_moves=MAX_MODEL_MOVES, deterministic=True, view=None):
    if view is None:
        view = GameView(_mutable_obs(obs))
    moves = []
    for _ in range(max_moves):
        action_mask = view.action_mask(SAFETY_MARGIN)
        if not action_mask.any():
            break
        policy = _np_action_policy(view.edge_features, action_mask)
        if deterministic:
            action_idx = int(np.argmax(policy))
        else:
            action_idx = int(np.random.choice(policy.shape[0], p=policy))
        stop_idx = view.n_max * view.n_max
        if action_idx == stop_idx:
            break
        src_slot = action_idx // view.n_max
        tgt_slot = action_idx % view.n_max
        ships = view.deterministic_ship_count(src_slot, tgt_slot, SAFETY_MARGIN)
        action = view.apply_planned_move(src_slot, tgt_slot, ships)
        if action is None:
            break
        moves.append(action)
    return moves


class StatefulNumpyModelAgent:
    def __init__(self, max_moves=MAX_MODEL_MOVES, deterministic=True):
        self.max_moves = max_moves
        self.deterministic = deterministic
        self._view = None

    def __call__(self, obs):
        mut = _mutable_obs(obs)
        if self._view is None:
            self._view = GameView(mut)
        else:
            self._view.update_from_obs(mut)
        return np_model_agent_actions(
            mut, max_moves=self.max_moves, deterministic=self.deterministic, view=self._view
        )


# --- Kaggle entrypoint ---
def agent(obs, config=None):
    global _STATEFUL_NP_AGENT, _STATEFUL_NP_PLAYER, _LAST_STEP
    player = _get(obs, 'player', 0)
    step = int(_get(obs, 'step', 0) or 0)
    if (_STATEFUL_NP_AGENT is None or _STATEFUL_NP_PLAYER != player
            or (_LAST_STEP is not None and step <= _LAST_STEP)):
        _STATEFUL_NP_AGENT = StatefulNumpyModelAgent(max_moves=1, deterministic=True)
        _STATEFUL_NP_PLAYER = player
    _LAST_STEP = step
    return _STATEFUL_NP_AGENT(obs)
